class TacticalSerial:
    def connect(self) -> bool:
        """Attempt to connect to CONFIG['SERIAL_PORT'] at CONFIG['BAUD_RATE'].
           Returns True if successful."""

    def force_reconnect(self) -> bool:
        """Bypass the 5-second reconnect cooldown.
           Used by Dashboard RECONNECT button."""

    def send_target(self, pan: float, tilt: float) -> None:
        """Dispatch a servo command: 'P{pan}T{tilt}L{laser_state}\\n'
           Thread-safe — uses internal lock. Respects 15ms rate limit."""

    def toggle_laser(self) -> int:
        """Toggle laser state (0→1 or 1→0). Returns new state.
           Intent is preserved: if ESP32 drops, laser state is restored on reconnect."""

    def force_laser(self, state: int) -> None:
        """Force laser to 0 (OFF) or 1 (ON) directly."""

    def toggle_alarm(self, state: int) -> None:
        """Send B1 (buzzer on) or B0 (buzzer off) to ESP32."""

    def is_connected(self) -> bool:
        """Returns True if serial port is open and heartbeat received recently."""

    def get_current_angles(self) -> tuple:
        """Returns last known (pan, tilt) angles from heartbeat/ACK."""

    def close(self) -> None:
        """Safe shutdown — sends home command, closes port, stops monitor thread."""
